class ConnectionPool {
public:
    explicit ConnectionPool(const ConnectionConfig& config)
        : config_(config)
        , next_id_(1)
        , shutdown_(false)
        , total_connections_(0)
    {
#ifdef _WIN32
        WSADATA wsa_data;
        if (WSAStartup(MAKEWORD(2, 2), &wsa_data) != 0) {
            throw std::runtime_error("WSAStartup failed");
        }
#endif
    }

    ~ConnectionPool() {
        shutdown();
#ifdef _WIN32
        WSACleanup();
#endif
    }

    // Non-copyable, non-movable
    ConnectionPool(const ConnectionPool&) = delete;
    ConnectionPool& operator=(const ConnectionPool&) = delete;

    bool initialize(size_t initial_connections = 0) {
        std::lock_guard<std::mutex> lock(pool_mutex_);

        if (initial_connections > config_.max_pool_size) {
            initial_connections = config_.max_pool_size;
        }

        for (size_t i = 0; i < initial_connections; ++i) {
            auto conn = create_connection();
            if (conn && conn->connect()) {
                available_.push(conn.get());
                all_connections_[conn->id()] = std::move(conn);
                ++total_connections_;
            }
        }

        return true;
    }

    ConnectionHandle acquire(int timeout_ms = 5000) {
        std::unique_lock<std::mutex> lock(pool_mutex_);

        auto deadline = std::chrono::steady_clock::now() + std::chrono::milliseconds(timeout_ms);

        while (!shutdown_) {
            // Try to get an available connection
            while (!available_.empty()) {
                Connection* conn = available_.front();
                available_.pop();

                if (conn->state() == ConnectionState::Connected) {
                    conn->set_state(ConnectionState::InUse);
                    return ConnectionHandle(conn, [this](Connection* c) {
                        this->release_connection(c);
                    });
                }

                // Connection is stale, try to reconnect
                if (conn->reconnect()) {
                    conn->set_state(ConnectionState::InUse);
                    return ConnectionHandle(conn, [this](Connection* c) {
                        this->release_connection(c);
                    });
                }

                // Failed to reconnect, destroy it
                destroy_connection_locked(conn);
            }

            // No available connections, try to create a new one
            if (total_connections_ < config_.max_pool_size) {
                auto conn = create_connection();
                if (conn && conn->connect()) {
                    conn->set_state(ConnectionState::InUse);
                    Connection* raw = conn.get();
                    all_connections_[conn->id()] = std::move(conn);
                    ++total_connections_;
                    return ConnectionHandle(raw, [this](Connection* c) {
                        this->release_connection(c);
                    });
                }
            }

            // Wait for a connection to become available
            if (pool_cv_.wait_until(lock, deadline) == std::cv_status::timeout) {
                return ConnectionHandle(); // Timeout
            }
        }

        return ConnectionHandle(); // Shutdown
    }

    // Retry an operation with automatic reconnection
    template<typename Func>
    bool retry_with_connection(Func&& operation, int max_retries = -1) {
        if (max_retries < 0) {
            max_retries = config_.max_retries;
        }

        ConnectionHandle handle = acquire();
        if (!handle) {
            return false;
        }

        for (int attempt = 0; attempt <= max_retries; ++attempt) {
            try {
                if (operation(handle)) {
                    handle->reset_retry_count();
                    return true;
                }
            } catch (...) {
                // Operation threw an exception
            }

            // Check if we should retry
            if (attempt < max_retries) {
                handle->increment_retry_count();

                // Try to reconnect using the same handle
                if (handle->state() == ConnectionState::Error ||
                    handle->state() == ConnectionState::Disconnected) {
                    if (!handle->reconnect()) {
                        // Reconnection failed, get a new connection
                        handle.release();
                        std::this_thread::sleep_for(
                            std::chrono::milliseconds(config_.retry_delay_ms * (attempt + 1)));
                        handle = acquire();
                        if (!handle) {
                            return false;
                        }
                    }
                }

                std::this_thread::sleep_for(
                    std::chrono::milliseconds(config_.retry_delay_ms));
            }
        }

        return false;
    }

    void shutdown() {
        std::lock_guard<std::mutex> lock(pool_mutex_);
        shutdown_ = true;

        // Disconnect all connections
        for (auto& pair : all_connections_) {
            if (pair.second) {
                pair.second->disconnect();
            }
        }

        // Clear the available queue
        while (!available_.empty()) {
            available_.pop();
        }

        all_connections_.clear();
        total_connections_ = 0;
        pool_cv_.notify_all();
    }

    size_t available_count() const {
        std::lock_guard<std::mutex> lock(pool_mutex_);
        return available_.size();
    }

    size_t total_count() const {
        std::lock_guard<std::mutex> lock(pool_mutex_);
        return total_connections_;
    }

    // Evict idle connections older than max_idle_ms
    void evict_idle(int max_idle_ms) {
        std::lock_guard<std::mutex> lock(pool_mutex_);
        auto now = std::chrono::steady_clock::now();
        auto threshold = std::chrono::milliseconds(max_idle_ms);

        std::queue<Connection*> keep;
        while (!available_.empty()) {
            Connection* conn = available_.front();
            available_.pop();

            auto idle_time = std::chrono::duration_cast<std::chrono::milliseconds>(
                now - conn->last_used());

            if (idle_time > threshold) {
                destroy_connection_locked(conn);
            } else {
                keep.push(conn);
            }
        }
        available_ = std::move(keep);
    }

private:
    std::unique_ptr<Connection> create_connection() {
        Connection::Id id = next_id_++;
        return std::make_unique<Connection>(id, config_);
    }

    void release_connection(Connection* conn) {
        if (!conn) return;

        std::lock_guard<std::mutex> lock(pool_mutex_);

        if (shutdown_) {
            destroy_connection_locked(conn);
            return;
        }

        if (conn->state() == ConnectionState::Error) {
            // Try to reconnect before returning to pool
            if (conn->reconnect()) {
                conn->set_state(ConnectionState::Connected);
                available_.push(conn);
            } else {
                destroy_connection_locked(conn);
            }
        } else if (conn->state() == ConnectionState::InUse ||
                   conn->state() == ConnectionState::Connected) {
            conn->set_state(ConnectionState::Connected);
            available_.push(conn);
        } else {
            // Disconnected state
            destroy_connection_locked(conn);
        }

        pool_cv_.notify_one();
    }

    void destroy_connection_locked(Connection* conn) {
        if (!conn) return;

        auto it = all_connections_.find(conn->id());
        if (it != all_connections_.end()) {
            it->second->disconnect();
            all_connections_.erase(it);
            if (total_connections_ > 0) {
                --total_connections_;
            }
        }
    }

    ConnectionConfig config_;
    std::atomic<Connection::Id> next_id_;
    std::atomic<bool> shutdown_;
    size_t total_connections_;

    mutable std::mutex pool_mutex_;
    std::condition_variable pool_cv_;

    std::queue<Connection*> available_;
    std::unordered_map<Connection::Id, std::unique_ptr<Connection>> all_connections_;
};

class NetworkClient {
public:
    explicit NetworkClient(const ConnectionConfig& config)
        : config_(config)
        , pool_(config)
    {}

    bool initialize(size_t initial_pool_size = 4) {
        return pool_.initialize(initial_pool_size);
    }

    void shutdown() {
        pool_.shutdown();
    }

    // Send data with automatic retry
    bool send(const uint8_t* data, size_t length) {
        if (!data || length == 0) return false;

        return pool_.retry_with_connection([data, length](ConnectionHandle& handle) -> bool {
            ssize_t sent = handle->send_data(data, length);
            return sent == static_cast<ssize_t>(length);
        });
    }

    // Send string data
    bool send(const std::string& data) {
        return send(reinterpret_cast<const uint8_t*>(data.data()), data.size());
    }

    // Receive data with automatic retry
    ssize_t receive(uint8_t* buffer, size_t max_length) {
        if (!buffer || max_length == 0) return -1;

        ssize_t result = -1;
        pool_.retry_with_connection([buffer, max_length, &result](ConnectionHandle& handle) -> bool {
            result = handle->recv_data(buffer, max_length);
            return result > 0;
        });
        return result;
    }

    // Send and receive with the same connection
    bool send_receive(const uint8_t* send_data, size_t send_length,
                      uint8_t* recv_buffer, size_t recv_max_length,
                      ssize_t& bytes_received) {
        if (!send_data || send_length == 0 || !recv_buffer || recv_max_length == 0) {
            return false;
        }

        return pool_.retry_with_connection(
            [send_data, send_length, recv_buffer, recv_max_length, &bytes_received]
            (ConnectionHandle& handle) -> bool {
                ssize_t sent = handle->send_data(send_data, send_length);
                if (sent != static_cast<ssize_t>(send_length)) {
                    return false;
                }

                bytes_received = handle->recv_data(recv_buffer, recv_max_length);
                return bytes_received > 0;
            });
    }

    // Get a raw connection handle for custom operations
    ConnectionHandle acquire_connection(int timeout_ms = 5000) {
        return pool_.acquire(timeout_ms);
    }

    // Pool statistics
    size_t available_connections() const { return pool_.available_count(); }
    size_t total_connections() const { return pool_.total_count(); }

    // Maintenance
    void evict_idle_connections(int max_idle_ms = 60000) {
        pool_.evict_idle(max_idle_ms);
    }

private:
    ConnectionConfig config_;
    ConnectionPool pool_;
};

// Example usage and test
int main() {
    ConnectionConfig config;
    config.host = "127.0.0.1";
    config.port = 8080;
    config.max_pool_size = 10;
    config.connect_timeout_ms = 3000;
    config.read_timeout_ms = 5000;
    config.write_timeout_ms = 5000;
    config.max_retries = 3;
    config.retry_delay_ms = 200;

    NetworkClient client(config);

    std::cout << "Initializing network client..." << std::endl;

    // Initialize with 0 pre-created connections (lazy creation)
    if (!client.initialize(0)) {
        std::cerr << "Failed to initialize client" << std::endl;
        return 1;
    }

    std::cout << "Client initialized. Pool size: " << client.total_connections() << std::endl;

    // Example: Try to send data (will fail if no server is running, but demonstrates the API)
    std::string message = "Hello, Server!";
    std::cout << "Attempting to send: " << message << std::endl;

    bool sent = client.send(message);
    if (sent) {
        std::cout << "Message sent successfully" << std::endl;

        uint8_t buffer[4096];
        ssize_t received = client.receive(buffer, sizeof(buffer) - 1);
        if (received > 0) {
            buffer[received] = '\0';
            std::cout << "Received: " << reinterpret_cast<char*>(buffer) << std::endl;
        }
    } else {
        std::cout << "Could not send message (no server running - this is expected in demo)" << std::endl;
    }

    // Example: Using retry_with_connection for custom logic
    std::cout << "\nDemonstrating retry mechanism..." << std::endl;

    auto handle = client.acquire_connection(1000);
    if (handle) {
        std::cout << "Acquired connection handle with ID: " << handle.id() << std::endl;
        // Handle is automatically released when it goes out of scope
    } else {
        std::cout << "Could not acquire connection (expected if no server)" << std::endl;
    }

    std::cout << "\nPool stats - Available: " << client.available_connections()
              << ", Total: " << client.total_connections() << std::endl;

    // Cleanup
    client.evict_idle_connections(0); // Evict all idle connections
    client.shutdown();

    std::cout << "Client shut down cleanly." << std::endl;
    return 0;
}